const t=JSON.parse('{"key":"v-6399b926","path":"/guide/tos.html","title":"SuzuBot 服务协议","lang":"zh-CN","frontmatter":{"order":3,"description":"更新日期：2023-01-19 本页中的服务协议阐述了您与 SuzuBot 之间关于使用 SuzuBot 以及其服务的关系。 邀请 SuzuBot 进入群组、添加 SuzuBot 好友或主动使用 SuzuBot 的任何功能均视为您已经阅读并同意以下条款，如果您不同意以下条款，您就无法使用 SuzuBot 提供的所有服务。 您可以在任何时候通过访问本页来...","head":[["meta",{"property":"og:url","content":"https://docs.suzubot.top/guide/tos.html"}],["meta",{"property":"og:site_name","content":"SuzuBot"}],["meta",{"property":"og:title","content":"SuzuBot 服务协议"}],["meta",{"property":"og:description","content":"更新日期：2023-01-19 本页中的服务协议阐述了您与 SuzuBot 之间关于使用 SuzuBot 以及其服务的关系。 邀请 SuzuBot 进入群组、添加 SuzuBot 好友或主动使用 SuzuBot 的任何功能均视为您已经阅读并同意以下条款，如果您不同意以下条款，您就无法使用 SuzuBot 提供的所有服务。 您可以在任何时候通过访问本页来..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-04-18T18:23:34.000Z"}],["meta",{"property":"article:author","content":"AkulaKirov"}],["meta",{"property":"article:modified_time","content":"2023-04-18T18:23:34.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"SuzuBot 服务协议\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-04-18T18:23:34.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"AkulaKirov\\",\\"url\\":\\"https://akula.moe/\\"}]}"]]},"headers":[{"level":2,"title":"1. 术语解释","slug":"_1-术语解释","link":"#_1-术语解释","children":[]},{"level":2,"title":"2. 许可和使用限制","slug":"_2-许可和使用限制","link":"#_2-许可和使用限制","children":[{"level":3,"title":"2.1 在使用 SuzuBot 的服务前，您应当知晓 SuzuBot 服务的各项使用方法以及正确命令格式。您应当知晓，任何人没有任何义务来指导您使用 SuzuBot 的服务。","slug":"_2-1-在使用-suzubot-的服务前-您应当知晓-suzubot-服务的各项使用方法以及正确命令格式。您应当知晓-任何人没有任何义务来指导您使用-suzubot-的服务。","link":"#_2-1-在使用-suzubot-的服务前-您应当知晓-suzubot-服务的各项使用方法以及正确命令格式。您应当知晓-任何人没有任何义务来指导您使用-suzubot-的服务。","children":[]},{"level":3,"title":"2.2 使用 SuzuBot 的服务需要您具有理解自身行为的基本能力，并且知晓和承担使用服务带来的结果。","slug":"_2-2-使用-suzubot-的服务需要您具有理解自身行为的基本能力-并且知晓和承担使用服务带来的结果。","link":"#_2-2-使用-suzubot-的服务需要您具有理解自身行为的基本能力-并且知晓和承担使用服务带来的结果。","children":[]},{"level":3,"title":"2.3 将 SuzuBot 拉入群组前，请确认您是该群的管理员或拥有者，或该邀请行为已得到多数管理员的同意。","slug":"_2-3-将-suzubot-拉入群组前-请确认您是该群的管理员或拥有者-或该邀请行为已得到多数管理员的同意。","link":"#_2-3-将-suzubot-拉入群组前-请确认您是该群的管理员或拥有者-或该邀请行为已得到多数管理员的同意。","children":[]},{"level":3,"title":"2.4 您同意不得展开和从事以下行为","slug":"_2-4-您同意不得展开和从事以下行为","link":"#_2-4-您同意不得展开和从事以下行为","children":[]},{"level":3,"title":"2.5 我们保留在这些条款下未明确授予您的任何权利。","slug":"_2-5-我们保留在这些条款下未明确授予您的任何权利。","link":"#_2-5-我们保留在这些条款下未明确授予您的任何权利。","children":[]}]},{"level":2,"title":"3. 隐私","slug":"_3-隐私","link":"#_3-隐私","children":[{"level":3,"title":"3.1 使用 SuzuBot 的服务将会收集和记录有关您使用 SuzuBot 服务的信息，包括但不限于使用次数，使用场合，使用时间，部分需要绑定的功能保存的数据。","slug":"_3-1-使用-suzubot-的服务将会收集和记录有关您使用-suzubot-服务的信息-包括但不限于使用次数-使用场合-使用时间-部分需要绑定的功能保存的数据。","link":"#_3-1-使用-suzubot-的服务将会收集和记录有关您使用-suzubot-服务的信息-包括但不限于使用次数-使用场合-使用时间-部分需要绑定的功能保存的数据。","children":[]},{"level":3,"title":"3.2 SuzuBot 的部分服务可能使用了第三方 API，这些服务保存的数据将会以业界标准的加密方式进行通信传输以用于为您提供服务。","slug":"_3-2-suzubot-的部分服务可能使用了第三方-api-这些服务保存的数据将会以业界标准的加密方式进行通信传输以用于为您提供服务。","link":"#_3-2-suzubot-的部分服务可能使用了第三方-api-这些服务保存的数据将会以业界标准的加密方式进行通信传输以用于为您提供服务。","children":[]}]},{"level":2,"title":"4. 服务的终止","slug":"_4-服务的终止","link":"#_4-服务的终止","children":[{"level":3,"title":"4.1 若发现您从事第2节中的任何行为，我们有权利终止对您进行限制。","slug":"_4-1-若发现您从事第2节中的任何行为-我们有权利终止对您进行限制。","link":"#_4-1-若发现您从事第2节中的任何行为-我们有权利终止对您进行限制。","children":[]},{"level":3,"title":"4.2 若您组织或者参与了对 SuzuBot 以及其开发人员无故进行骚扰、威胁、污蔑、诋毁等恶意行为，我们有权利终止对您进行限制。","slug":"_4-2-若您组织或者参与了对-suzubot-以及其开发人员无故进行骚扰、威胁、污蔑、诋毁等恶意行为-我们有权利终止对您进行限制。","link":"#_4-2-若您组织或者参与了对-suzubot-以及其开发人员无故进行骚扰、威胁、污蔑、诋毁等恶意行为-我们有权利终止对您进行限制。","children":[]},{"level":3,"title":"4.3 若发现您从事没有在这些条款中列出，但可能会影响他人自由使用 SuzuBot 服务的行为，我们有权利终止对您进行限制。","slug":"_4-3-若发现您从事没有在这些条款中列出-但可能会影响他人自由使用-suzubot-服务的行为-我们有权利终止对您进行限制。","link":"#_4-3-若发现您从事没有在这些条款中列出-但可能会影响他人自由使用-suzubot-服务的行为-我们有权利终止对您进行限制。","children":[]},{"level":3,"title":"4.4 对于首次违反协议的行为，我们会进行口头警告。对于多次违反协议的行为，我们将会加大限制的力度。","slug":"_4-4-对于首次违反协议的行为-我们会进行口头警告。对于多次违反协议的行为-我们将会加大限制的力度。","link":"#_4-4-对于首次违反协议的行为-我们会进行口头警告。对于多次违反协议的行为-我们将会加大限制的力度。","children":[]}]},{"level":2,"title":"5. 责任和约束","slug":"_5-责任和约束","link":"#_5-责任和约束","children":[{"level":3,"title":"5.1 我们不对您在使用 SuzuBot 的服务的过程中可能发生的任何损失负责，不论这些损失是何种形式的。","slug":"_5-1-我们不对您在使用-suzubot-的服务的过程中可能发生的任何损失负责-不论这些损失是何种形式的。","link":"#_5-1-我们不对您在使用-suzubot-的服务的过程中可能发生的任何损失负责-不论这些损失是何种形式的。","children":[]},{"level":3,"title":"5.2 SuzuBot 的部分服务使用的第三方 API 可能会违反您与第三方的服务条款，您将自行承担使用这些服务带来的一切损失。","slug":"_5-2-suzubot-的部分服务使用的第三方-api-可能会违反您与第三方的服务条款-您将自行承担使用这些服务带来的一切损失。","link":"#_5-2-suzubot-的部分服务使用的第三方-api-可能会违反您与第三方的服务条款-您将自行承担使用这些服务带来的一切损失。","children":[]}]},{"level":2,"title":"6. 联络和沟通","slug":"_6-联络和沟通","link":"#_6-联络和沟通","children":[{"level":3,"title":"6.1 如果您对 SuzuBot 以及其服务有任何建议和反馈，请通过 SuzuBot 认领群来进行反馈，或发送邮件至 photonspk@gmail.com，您需要清晰的表达您的需求和意见以方便我们改善 SuzuBot 以及其服务。","slug":"_6-1-如果您对-suzubot-以及其服务有任何建议和反馈-请通过-suzubot-认领群来进行反馈-或发送邮件至-photonspk-gmail-com-您需要清晰的表达您的需求和意见以方便我们改善-suzubot-以及其服务。","link":"#_6-1-如果您对-suzubot-以及其服务有任何建议和反馈-请通过-suzubot-认领群来进行反馈-或发送邮件至-photonspk-gmail-com-您需要清晰的表达您的需求和意见以方便我们改善-suzubot-以及其服务。","children":[]}]}],"git":{"createdTime":1681842214000,"updatedTime":1681842214000,"contributors":[{"name":"AkulaKirov","email":"photonspk@gmail.com","commits":1}]},"readingTime":{"minutes":4.01,"words":1204},"filePathRelative":"guide/tos.md","localizedDate":"2023年4月18日","autoDesc":true}');export{t as data};
